def update_pkg(self:Kosha, pkg:str, embed=True, exts=code_exts, efn=embedder, verbose=True, **kwargs):
	'Update package metadata in the packages table.'
	assert (o:= spec(pkg)), f'pkg {pkg} is not in environment'
